sql:
SELECT DISTINCT data_size
FROM task_performance_logs
ORDER BY data_size ASC;

SELECT AVG(throughput) AS avg_throughput
FROM task_performance_logs
WHERE test = 'write' AND environment = 'production' AND version = '2.4.0';

SELECT DISTINCT environment, test
FROM task_performance_logs
WHERE task_status = 'completed' AND error_code IS NULL;

external_knowledge:
- 'voyages' metaphorically refers to tasks;
- 'write' refers to the type of test in the database;
- 'completed' refers to the task status;
- 'ebb of time spent' metaphorically refers to latency;
- 'waves of their throughput' metaphorically refers to the throughput of tasks;
- 'storms' metaphorically refers to errors encountered by tasks;
- 'task ID' is the unique identifier for each task.
